@WebService(targetNamespace = "http://bank.example.com/soap", serviceName = "BankingService", portName = "BankingPort")
public class BankingService {

    @WebMethod
    public TransactionResponse processTransaction(@WebParam(name = "request") TransactionRequest request) {
        TransactionResponse response = new TransactionResponse();
        response.setTransactionId(request.getTransactionId());
        response.setStatus("APPROVED");
        response.setMessage("Transaction processed successfully");
        response.setApprovedAmount(request.getAmount());
        return response;
    }

    public static void main(String[] args) throws Exception {
        Endpoint endpoint = Endpoint.create(new BankingService());
        endpoint.publish("http://0.0.0.0:8080/banking");
    }
}

@XmlRootElement(name = "TransactionRequest")
@XmlAccessorType(XmlAccessType.FIELD)
@XmlType(name = "TransactionRequest", propOrder = {"transactionId", "accountNumber", "amount", "currency", "signedPayload"})
class TransactionRequest {
    @XmlElement(required = true)
    private String transactionId;

    @XmlElement(required = true)
    private String accountNumber;

    @XmlElement(required = true)
    private BigDecimal amount;

    @XmlElement(required = true)
    private String currency;

    @XmlElement(required = false)
    private String signedPayload;

    public String getTransactionId() { return transactionId; }
    public void setTransactionId(String transactionId) { this.transactionId = transactionId; }
    public String getAccountNumber() { return accountNumber; }
    public void setAccountNumber(String accountNumber) { this.accountNumber = accountNumber; }
    public BigDecimal getAmount() { return amount; }
    public void setAmount(BigDecimal amount) { this.amount = amount; }
    public String getCurrency() { return currency; }
    public void setCurrency(String currency) { this.currency = currency; }
    public String getSignedPayload() { return signedPayload; }
    public void setSignedPayload(String signedPayload) { this.signedPayload = signedPayload; }
}

@XmlRootElement(name = "TransactionResponse")
@XmlAccessorType(XmlAccessType.FIELD)
@XmlType(name = "TransactionResponse", propOrder = {"transactionId", "status", "message", "approvedAmount"})
class TransactionResponse {
    @XmlElement(required = true)
    private String transactionId;

    @XmlElement(required = true)
    private String status;

    @XmlElement(required = true)
    private String message;

    @XmlElement(required = false)
    private BigDecimal approvedAmount;

    public String getTransactionId() { return transactionId; }
    public void setTransactionId(String transactionId) { this.transactionId = transactionId; }
    public String getStatus() { return status; }
    public void setStatus(String status) { this.status = status; }
    public String getMessage() { return message; }
    public void setMessage(String message) { this.message = message; }
    public BigDecimal getApprovedAmount() { return approvedAmount; }
    public void setApprovedAmount(BigDecimal approvedAmount) { this.approvedAmount = approvedAmount; }
}

class WsSecurityTransactionHandler implements SOAPHandler<SOAPMessageContext> {

    private final SignatureVerifier signatureVerifier = new SignatureVerifier();

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.FALSE.equals(outbound)) {
            try {
                SOAPMessage message = context.getMessage();
                Document document = messageToDocument(message);
                Element signedElement = XmlSecurityUtil.extractSignedElement(document);
                if (signedElement == null) {
                    throw new SOAPFaultException(SOAPFaultBuilder.createSOAPFaultMessage(
                            javax.xml.soap.SOAPConstants.SOAP_1_1_PROTOCOL,
                            "Missing signed element",
                            "Client"));
                }
                boolean valid = signatureVerifier.verify(document);
                if (!valid) {
                    throw new SOAPFaultException(SOAPFaultBuilder.createSOAPFaultMessage(
                            javax.xml.soap.SOAPConstants.SOAP_1_1_PROTOCOL,
                            "Invalid XML Signature",
                            "Client"));
                }
                TransactionRequest request = XmlSecurityUtil.parseTransactionRequest(document);
                context.put("BANK_TRANSACTION_REQUEST", request);
                context.setScope("BANK_TRANSACTION_REQUEST", MessageContext.Scope.APPLICATION);
            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        }
        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    private Document messageToDocument(SOAPMessage message) throws SOAPException, ParserConfigurationException, java.io.IOException, org.xml.sax.SAXException {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setExpandEntityReferences(false);
        Document doc = dbf.newDocumentBuilder().newDocument();
        message.getSOAPPart().getContent().copyTo(new DOMSource(doc));
        return message.getSOAPPart().getEnvelope().getOwnerDocument();
    }
}

class SignatureVerifier {

    public boolean verify(Document document) throws Exception {
        Element signatureElement = XmlSecurityUtil.findSignatureElement(document);
        if (signatureElement == null) {
            return false;
        }
        DOMValidateContext validateContext = new DOMValidateContext(new KeyValueKeySelector(), signatureElement);
        validateContext.setProperty("org.jcp.xml.dsig.secureValidation", Boolean.TRUE);
        XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
        XMLSignature signature = factory.unmarshalXMLSignature(validateContext);
        return signature.validate(validateContext);
    }
}

class KeyValueKeySelector extends javax.xml.crypto.KeySelector {
    @Override
    public javax.xml.crypto.KeySelectorResult select(javax.xml.crypto.dsig.keyinfo.KeyInfo keyInfo, javax.xml.crypto.KeySelector.Purpose purpose, javax.xml.crypto.AlgorithmMethod method, javax.xml.crypto.XMLCryptoContext context) throws javax.xml.crypto.KeySelectorException {
        if (keyInfo == null) {
            throw new javax.xml.crypto.KeySelectorException("No KeyInfo");
        }
        for (Object info : keyInfo.getContent()) {
            if (info instanceof javax.xml.crypto.dsig.keyinfo.KeyValue) {
                try {
                    PublicKey pk = ((javax.xml.crypto.dsig.keyinfo.KeyValue) info).getPublicKey();
                    return () -> pk;
                } catch (Exception e) {
                    throw new javax.xml.crypto.KeySelectorException(e);
                }
            }
            if (info instanceof javax.xml.crypto.dsig.keyinfo.X509Data) {
                javax.xml.crypto.dsig.keyinfo.X509Data x509Data = (javax.xml.crypto.dsig.keyinfo.X509Data) info;
                for (Object data : x509Data.getContent()) {
                    if (data instanceof X509Certificate) {
                        PublicKey pk = ((X509Certificate) data).getPublicKey();
                        return () -> pk;
                    }
                }
            }
        }
        throw new javax.xml.crypto.KeySelectorException("No suitable key found");
    }
}

class XmlSecurityUtil {

    public static Element findSignatureElement(Document document) {
        NodeList list = document.getElementsByTagNameNS(javax.xml.crypto.dsig.XMLSignature.XMLNS, "Signature");
        return list.getLength() > 0 ? (Element) list.item(0) : null;
    }

    public static Element extractSignedElement(Document document) {
        NodeList list = document.getElementsByTagNameNS("http://bank.example.com/soap", "TransactionRequest");
        if (list.getLength() > 0) {
            return (Element) list.item(0);
        }
        list = document.getElementsByTagName("TransactionRequest");
        return list.getLength() > 0 ? (Element) list.item(0) : null;
    }

    public static TransactionRequest parseTransactionRequest(Document document) throws Exception {
        Element element = extractSignedElement(document);
        if (element == null) {
            throw new IllegalArgumentException("TransactionRequest not found");
        }
        TransactionRequest request = new TransactionRequest();
        request.setTransactionId(getChildText(element, "transactionId"));
        request.setAccountNumber(getChildText(element, "accountNumber"));
        String amount = getChildText(element, "amount");
        if (amount != null && !amount.isEmpty()) {
            request.setAmount(new BigDecimal(amount));
        }
        request.setCurrency(getChildText(element, "currency"));
        request.setSignedPayload(element.getTextContent());
        return request;
    }

    private static String getChildText(Element parent, String localName) {
        NodeList list = parent.getElementsByTagName(localName);
        if (list.getLength() == 0) {
            list = parent.getElementsByTagNameNS("*", localName);
        }
        if (list.getLength() == 0) {
            return null;
        }
        return list.item(0).getTextContent();
    }
}

